'use client';

import React, { useEffect, useState } from 'react';
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectTrigger, SelectValue, SelectContent, SelectItem } from '@/components/ui/select';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Pencil, Plus, Trash } from 'lucide-react';
// import axios from 'axios';

interface Plant {
  id: string;
  name: string;
}

interface CarePoint {
  _id: string;
  plant: string;
  title: string;
  description: string;
  helpPoint?: string;
}

export default function GuidePage() {
  const [plants, setPlants] = useState<Plant[]>([]);
  const [carePoints, setCarePoints] = useState<CarePoint[]>([]);
  const [openDialog, setOpenDialog] = useState(false);
  const [editingPoint, setEditingPoint] = useState<CarePoint | null>(null);

  const [form, setForm] = useState({
    plant: '',
    title: '',
    description: '',
    helpPoint: '',
  });

  useEffect(() => {
    // Fetch dummy plant list (replace with API)
    // axios.get('/api/plants', { withCredentials: true }).then(res => setPlants(res.data));
    setPlants([
      { id: 'p1', name: 'Monstera Deliciosa' },
      { id: 'p2', name: 'Snake Plant' },
      { id: 'p3', name: 'Aloe Vera' },
    ]);

    // Dummy data for existing care points
    setCarePoints([
      {
        _id: 'c1',
        plant: 'Monstera Deliciosa',
        title: 'Watering Schedule',
        description: 'Water once a week when soil is 50% dry.',
        helpPoint: 'Avoid overwatering during winter.',
      },
      {
        _id: 'c2',
        plant: 'Snake Plant',
        title: 'Sunlight Requirement',
        description: 'Keep in bright indirect sunlight.',
        helpPoint: 'Rotate the plant weekly for even growth.',
      },
    ]);
  }, []);

  const openAddDialog = () => {
    setEditingPoint(null);
    setForm({ plant: '', title: '', description: '', helpPoint: '' });
    setOpenDialog(true);
  };

  const openEditDialog = (point: CarePoint) => {
    setEditingPoint(point);
    setForm({
      plant: point.plant,
      title: point.title,
      description: point.description,
      helpPoint: point.helpPoint || '',
    });
    setOpenDialog(true);
  };

  const handleSave = async () => {
    if (!form.plant || !form.title || !form.description) {
      alert('Please fill all required fields');
      return;
    }

    try {
      if (editingPoint) {
        // Update existing (API example)
        // await axios.put(`/api/carepoints/${editingPoint._id}`, form, { withCredentials: true });

        setCarePoints((prev) =>
          prev.map((p) =>
            p._id === editingPoint._id ? { ...p, ...form } : p
          )
        );
        alert('Care point updated');
      } else {
        // Add new (API example)
        // const res = await axios.post('/api/carepoints', form, { withCredentials: true });
        const newPoint = {
          _id: Math.random().toString(),
          ...form,
        };
        setCarePoints((prev) => [...prev, newPoint]);
        alert('Care point added');
      }

      setOpenDialog(false);
    } catch (err) {
      console.error(err);
      alert('Failed to save');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this care point?')) return;
    try {
      // await axios.delete(`/api/carepoints/${id}`, { withCredentials: true });
      setCarePoints((prev) => prev.filter((p) => p._id !== id));
    } catch (err) {
      console.error(err);
      alert('Failed to delete');
    }
  };

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold">Plant Care Guide</h1>
        <Button onClick={openAddDialog} className="bg-green-600 hover:bg-green-700">
          <Plus size={18} className="mr-1" /> Add Care Point
        </Button>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>All Care Points</CardTitle>
        </CardHeader>
        <CardContent>
          <ScrollArea className="max-h-[500px]">
            <table className="w-full text-sm md:text-base">
              <thead>
                <tr className="text-left border-b">
                  <th>Plant</th>
                  <th>Title</th>
                  <th>Description</th>
                  <th>Help Point</th>
                  <th className="text-center">Actions</th>
                </tr>
              </thead>
              <tbody>
                {carePoints.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="text-center py-4 text-gray-500">
                      No care points added yet.
                    </td>
                  </tr>
                ) : (
                  carePoints.map((point) => (
                    <tr key={point._id} className="border-t">
                      <td className="py-2 font-medium">{point.plant}</td>
                      <td className="py-2">{point.title}</td>
                      <td className="py-2 max-w-[250px] truncate">{point.description}</td>
                      <td className="py-2 text-gray-600">{point.helpPoint || '-'}</td>
                      <td className="py-2 flex justify-center gap-2">
                        <Button
                          size="sm"
                          className="bg-blue-600 text-white hover:bg-blue-700"
                          onClick={() => openEditDialog(point)}
                        >
                          <Pencil size={14} className="mr-1" /> Edit
                        </Button>
                        <Button
                          size="sm"
                          className="bg-red-600 text-white hover:bg-red-700"
                          onClick={() => handleDelete(point._id)}
                        >
                          <Trash size={14} className="mr-1" /> Delete
                        </Button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </ScrollArea>
        </CardContent>
      </Card>

      {/* Dialog for Add/Edit */}
      <Dialog open={openDialog} onOpenChange={setOpenDialog}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle>
              {editingPoint ? 'Edit Care Point' : 'Add New Care Point'}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-3">
            <Select
              value={form.plant}
              onValueChange={(v) => setForm({ ...form, plant: v })}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select Plant" />
              </SelectTrigger>
              <SelectContent>
                {plants.map((p) => (
                  <SelectItem key={p.id} value={p.name}>
                    {p.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Input
              placeholder="Title (e.g., Watering Tips)"
              value={form.title}
              onChange={(e) => setForm({ ...form, title: e.target.value })}
            />

            <Textarea
              placeholder="Description"
              value={form.description}
              onChange={(e) => setForm({ ...form, description: e.target.value })}
            />

            <Input
              placeholder="Optional: Help or Update Point"
              value={form.helpPoint}
              onChange={(e) => setForm({ ...form, helpPoint: e.target.value })}
            />
          </div>

          <DialogFooter className="flex justify-end mt-4">
            <Button variant="outline" onClick={() => setOpenDialog(false)}>
              Cancel
            </Button>
            <Button
              className="bg-green-600 hover:bg-green-700 text-white"
              onClick={handleSave}
            >
              {editingPoint ? 'Update' : 'Add'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
